import (
	addondiff "github.com/openmeterio/openmeter/openmeter/subscription/addon/diff"
	"github.com/openmeterio/openmeter/openmeter/subscription"
)

diffable, err := addondiff.GetDiffableFromAddon(subView, subsAdd)
if err != nil { return err }
if diffable == nil { return nil } // no instances

spec := subView.Spec
if err := spec.Apply(diffable.GetApplies(), subscription.ApplyContext{CurrentTime: now}); err != nil {
	return err
}
// later, to undo:
if err := spec.Apply(diffable.GetRestores(), subscription.ApplyContext{CurrentTime: now}); err != nil {
	return err
}

func (h *handler) GetSubscriptionAddon() GetSubscriptionAddonHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params GetSubscriptionAddonParams) (GetSubscriptionAddonRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return GetSubscriptionAddonRequest{}, err }
			return GetSubscriptionAddonRequest{
				SubscriptionID:      models.NamespacedID{Namespace: ns, ID: params.SubscriptionID},
				SubscriptionAddonID: models.NamespacedID{Namespace: ns, ID: params.SubscriptionAddonID},
			}, nil
		},
		func(ctx context.Context, req GetSubscriptionAddonRequest) (GetSubscriptionAddonResponse, error) {
			res, err := h.SubscriptionAddonService.Get(ctx, req.SubscriptionAddonID)
			if err != nil { return GetSubscriptionAddonResponse{}, err }
			view, err := h.SubscriptionService.GetView(ctx, req.SubscriptionID)
			if err != nil { return GetSubscriptionAddonResponse{}, err }
			return MapSubscriptionAddonToResponse(view, *res)
		},
		commonhttp.JSONResponseEncoderWithStatus[GetSubscriptionAddonResponse](http.StatusOK),
		httptransport.AppendOptions(h.Options, httptransport.WithOperationName("get-subscription-addon"))...,
	)
}

import (
	subscriptionaddonrepo "github.com/openmeterio/openmeter/openmeter/subscription/addon/repo"
)

repo := subscriptionaddonrepo.NewSubscriptionAddonRepo(dbClient)
id, err := repo.Create(ctx, ns, subscriptionaddon.CreateSubscriptionAddonRepositoryInput{
	AddonID:        addonID,
	SubscriptionID: subID,
})
// ctx carries the tx — repo.Create rebinds automatically via TransactingRepo

// From service.go — transaction.Run coordinates repo writes and event publish
return transaction.Run(ctx, s.cfg.TxManager, func(ctx context.Context) (*subscriptionaddon.SubscriptionAddon, error) {
	subAddID, err := s.cfg.SubAddRepo.Create(ctx, namespace, subscriptionaddon.CreateSubscriptionAddonRepositoryInput{
		AddonID: input.AddonID, SubscriptionID: input.SubscriptionID,
	})
	if err != nil { return nil, err }
	_, err = s.cfg.SubAddQtyRepo.Create(ctx, *subAddID, subscriptionaddon.CreateSubscriptionAddonQuantityRepositoryInput{
		ActiveFrom: input.InitialQuantity.ActiveFrom,
		Quantity:   input.InitialQuantity.Quantity,
	})
	if err != nil { return nil, err }
	subAdd, err := s.cfg.SubAddRepo.Get(ctx, *subAddID)
	if err != nil { return nil, err }
	s.cfg.Publisher.Publish(ctx, subscriptionaddon.NewCreatedEvent(ctx, sView.Customer, *subAdd))
	return subAdd, nil
})
